// Build PostgREST query for hot leads:
//   - lead_score >= threshold (default 80, configurable via $env.CLX_HOT_LEAD_SCORE)
//   - lead_status in the intent-signal set (Replied / Booking Sent / interest_detected)
//   - updated_at within the last N hours (default 24, configurable via $env.CLX_HOT_LEAD_WINDOW_HOURS)
const threshold = parseInt($env.CLX_HOT_LEAD_SCORE || '80', 10);
const windowHrs = parseInt($env.CLX_HOT_LEAD_WINDOW_HOURS || '24', 10);
const sinceIso  = new Date(Date.now() - windowHrs * 3600000).toISOString();
const qs = [
  'select=id,client_id,full_name,email,company,industry,city,product_type,lead_type,lead_status,lead_score,recommended_campaign_type,research_summary,likely_business_need,detected_signal,signal_confidence,assigned_to,booking_email_sent,interest_detected,updated_at,date_created',
  'lead_score=gte.' + threshold,
  'lead_status=in.(Replied,Booking%20Sent,Outreach%20Ready)',
  'updated_at=gte.' + encodeURIComponent(sinceIso),
  'order=updated_at.desc',
  'limit=50'
].join('&');
return { json: { qs: qs, threshold: threshold, window_hrs: windowHrs, since_iso: sinceIso } };

// Canonical allOf() — flatten array-split / single-row-unwrap.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const leads = allOf('Query Hot Leads');
const meta  = $('Build Query').first().json;

if (leads.length === 0) {
  // No-op tick — return single sentinel item so downstream code doesn't crash on empty input.
  return [{ json: { _no_hot_leads: true, threshold: meta.threshold, window_hrs: meta.window_hrs, since_iso: meta.since_iso } }];
}

const todayKey = new Date().toISOString().slice(0, 10);

// Map each lead to a sentinel_alerts INSERT body. aggregation_key uses
// hotlead-<lead_id>-<YYYY-MM-DD> so we never raise more than one alert
// per lead per day. Severity escalates with lead_score.
const now = new Date().toISOString();

return leads.map(function (l) {
  let severity = 'info';
  if ((l.lead_score || 0) >= 95) severity = 'critical';
  else if ((l.lead_score || 0) >= 90) severity = 'warning';

  const reasons = [];
  if ((l.lead_score || 0) >= meta.threshold) reasons.push('score=' + l.lead_score);
  if (l.lead_status === 'Replied') reasons.push('replied to outreach');
  if (l.lead_status === 'Booking Sent') reasons.push('Calendly sent — awaiting booking');
  if (l.lead_type === 'carrier_prospect') reasons.push('carrier_prospect');
  if (l.lead_type === 'advisor_candidate') reasons.push('advisor_candidate');
  if (l.detected_signal) reasons.push('signal: ' + l.detected_signal);

  const titlePrefix =
    l.lead_type === 'carrier_prospect'  ? '🏢 Hot carrier' :
    l.lead_type === 'advisor_candidate' ? '👤 Hot advisor' :
                                          '🔥 Hot lead';

  const title = titlePrefix + ' — ' + (l.company || 'Unknown') + ' (score ' + (l.lead_score || 0) + ')';

  const message = (l.full_name || 'Unknown contact') +
    (l.industry ? ' · ' + l.industry : '') +
    (l.city ? ' · ' + l.city : '') +
    ' — ' + reasons.join(' · ');

  return {
    json: {
      lead_id:         l.id,
      module_name:     'ciro',
      alert_type:      'hot_lead',
      severity:        severity,
      title:           title.slice(0, 200),
      message:         message.slice(0, 500),
      details: {
        lead_id:        l.id,
        client_id:      l.client_id || null,
        company:        l.company,
        full_name:      l.full_name,
        email:          l.email,
        industry:       l.industry,
        city:           l.city,
        lead_score:     l.lead_score,
        lead_status:    l.lead_status,
        lead_type:      l.lead_type || 'smb',
        product_type:   l.product_type,
        detected_signal:l.detected_signal,
        signal_confidence: l.signal_confidence,
        recommended_campaign_type: l.recommended_campaign_type,
        likely_business_need: l.likely_business_need,
        assigned_to:    l.assigned_to,
        booking_email_sent: l.booking_email_sent,
        interest_detected:  l.interest_detected,
        updated_at:     l.updated_at
      },
      aggregation_key: 'hotlead-' + l.id + '-' + todayKey,
      triggered_at:    now,
      status:          'open'
    }
  };
});
